import React, { useEffect, useMemo, useRef, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import {
  Alert,
  Badge,
  Button,
  Card,
  Col,
  Container,
  Form,
  Row,
  Spinner,
} from "react-bootstrap";
import api from "../services/api";

function EventDetailPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const ticketSectionRef = useRef(null);

  const [event, setEvent] = useState(null);
  const [ticketTypes, setTicketTypes] = useState([]);
  const [summary, setSummary] = useState(null);
  const [quantities, setQuantities] = useState({});
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const getStoredUser = () => {
    try {
      const rawUser = localStorage.getItem("user");
      if (!rawUser || rawUser === "undefined") return null;
      return JSON.parse(rawUser);
    } catch (error) {
      localStorage.removeItem("user");
      return null;
    }
  };

  const user = getStoredUser();

  const getBannerSrc = (bannerImage) => {
    if (!bannerImage) {
      return "https://via.placeholder.com/1200x700?text=Concert+Banner";
    }

    if (
      bannerImage.startsWith("http://") ||
      bannerImage.startsWith("https://")
    ) {
      return bannerImage;
    }

    return `/images/${bannerImage}`;
  };

  const getEventStatusText = (status) => {
    switch (status) {
      case "draft":
        return "Nháp";
      case "upcoming":
        return "Sắp mở bán";
      case "on_sale":
        return "Đang mở bán";
      case "paused":
        return "Tạm dừng";
      case "sold_out":
        return "Hết vé";
      case "ended":
        return "Đã kết thúc";
      case "cancelled":
        return "Đã hủy";
      default:
        return "Không xác định";
    }
  };

  const formatDateTime = (dateString) => {
    if (!dateString) return "Không có dữ liệu";

    const date = new Date(dateString);

    return date.toLocaleString("vi-VN", {
      weekday: "long",
      year: "numeric",
      month: "long",
      day: "numeric",
      hour: "2-digit",
      minute: "2-digit",
    });
  };

  useEffect(() => {
    const fetchEventDetail = async () => {
      try {
        setLoading(true);
        setError("");

        const response = await api.get(`/events/${id}/details`);

        if (response.data?.success && response.data?.data) {
          const payload = response.data.data;
          const eventData = payload.event || null;
          const ticketList = payload.ticketTypes || [];
          const summaryData = payload.summary || null;

          setEvent(eventData);
          setTicketTypes(ticketList);
          setSummary(summaryData);

          const initialQuantities = {};
          ticketList.forEach((ticket) => {
            initialQuantities[ticket.id] = 0;
          });
          setQuantities(initialQuantities);
        } else {
          setError("Không lấy được chi tiết sự kiện");
        }
      } catch (err) {
        console.error("Lỗi khi tải chi tiết sự kiện:", err);
        setError(
          err.response?.data?.message || "Lỗi khi tải chi tiết sự kiện"
        );
      } finally {
        setLoading(false);
      }
    };

    fetchEventDetail();
  }, [id]);

  const handleQuantityChange = (ticket, value) => {
    let quantity = Number(value);

    if (Number.isNaN(quantity) || quantity < 0) quantity = 0;

    const maxAllowed = Math.min(
      Number(ticket.available || 0),
      Number(ticket.max_per_order || 0)
    );

    if (quantity > maxAllowed) quantity = maxAllowed;

    setQuantities((prev) => ({
      ...prev,
      [ticket.id]: quantity,
    }));
  };

  const totalTickets = useMemo(() => {
    return ticketTypes.reduce((sum, ticket) => {
      return sum + Number(quantities[ticket.id] || 0);
    }, 0);
  }, [ticketTypes, quantities]);

  const totalAmount = useMemo(() => {
    return ticketTypes.reduce((sum, ticket) => {
      const qty = Number(quantities[ticket.id] || 0);
      return sum + qty * Number(ticket.price || 0);
    }, 0);
  }, [ticketTypes, quantities]);

  const minPrice = useMemo(() => {
    if (!ticketTypes.length) return 0;
    return Math.min(...ticketTypes.map((ticket) => Number(ticket.price || 0)));
  }, [ticketTypes]);

  const canBuy = ticketTypes.some(
    (ticket) =>
      Number(ticket.available || 0) > 0 &&
      Number(ticket.max_per_order || 0) > 0 &&
      ticket.status === "active"
  );

  const scrollToTickets = () => {
    if (ticketSectionRef.current) {
      ticketSectionRef.current.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  };

  const handleCreateOrder = async () => {
    try {
      setError("");
      setSuccess("");

      const token = localStorage.getItem("token");
      if (!token || !user) {
        navigate("/login");
        return;
      }

      const items = ticketTypes
        .filter((ticket) => Number(quantities[ticket.id] || 0) > 0)
        .map((ticket) => ({
          ticket_type_id: ticket.id,
          quantity: Number(quantities[ticket.id]),
        }));

      if (items.length === 0) {
        setError("Vui lòng chọn ít nhất 1 vé");
        scrollToTickets();
        return;
      }

      setSubmitting(true);

      const response = await api.post("/users/orders/create", { items });

      if (response.data?.success) {
        const orderId = response.data.data?.orderId;
        setSuccess("Đặt vé thành công, đang chuyển sang thanh toán...");

        setTimeout(() => {
          navigate(`/payment/${orderId}`);
        }, 700);
      } else {
        setError(response.data?.message || "Đặt vé thất bại");
      }
    } catch (err) {
      console.error("Lỗi tạo đơn hàng:", err);
      setError(err.response?.data?.message || "Đã xảy ra lỗi khi đặt vé");
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) {
    return (
      <div
        className="d-flex justify-content-center align-items-center"
        style={{ minHeight: "70vh" }}
      >
        <Spinner animation="border" variant="light" />
      </div>
    );
  }

  if (error && !event) {
    return (
      <Container className="user-shell text-center text-white">
        <h3>{error}</h3>
      </Container>
    );
  }

  if (!event) {
    return (
      <Container className="user-shell text-center text-white">
        <h3>Không tìm thấy sự kiện này.</h3>
      </Container>
    );
  }

  return (
    <div className="tb-detail-page">
      <Container fluid="xl" className="tb-detail-container">
        {error && <Alert variant="danger">{error}</Alert>}
        {success && <Alert variant="success">{success}</Alert>}

        <section className="tb-detail-hero">
          <Row className="g-0">
            <Col lg={4}>
              <div className="tb-detail-info-panel">
                <div className="tb-detail-title">{event.title}</div>

                <div className="tb-detail-meta-item">
                  <span className="tb-detail-icon">🗓</span>
                  <div>
                    <div className="tb-detail-meta-highlight">
                      {formatDateTime(event.event_date)}
                    </div>
                  </div>
                </div>

                <div className="tb-detail-meta-item">
                  <span className="tb-detail-icon">📍</span>
                  <div>
                    <div className="tb-detail-meta-highlight">
                      {getEventStatusText(event.status)}
                    </div>
                    <div className="tb-detail-meta-sub">{event.location}</div>
                  </div>
                </div>

                <div className="tb-detail-divider" />

                <div className="tb-detail-price-row">
                  <span>Giá từ</span>
                  <strong>{minPrice.toLocaleString("vi-VN")} đ</strong>
                </div>

                <Button
                  className="tb-buy-main-btn"
                  onClick={scrollToTickets}
                >
                  Mua vé ngay
                </Button>
              </div>
            </Col>

            <Col lg={8}>
              <div className="tb-detail-banner-wrap">
                <img
                  src={getBannerSrc(event.banner_image)}
                  alt={event.title}
                  className="tb-detail-banner"
                  onError={(e) => {
                    e.target.src =
                      "https://via.placeholder.com/1200x700?text=Concert+Banner";
                  }}
                />
              </div>
            </Col>
          </Row>
        </section>

        <Row className="g-4 mt-1">
          <Col lg={9}>
            <section ref={ticketSectionRef} className="tb-ticket-section">
              <div className="tb-ticket-section-title">Thông tin vé</div>

              {ticketTypes.length === 0 ? (
                <div className="tb-ticket-empty">
                  Hiện chưa có loại vé nào cho sự kiện này.
                </div>
              ) : (
                <div className="tb-ticket-list">
                  {ticketTypes.map((ticket) => {
                    const maxAllowed = Math.min(
                      Number(ticket.available || 0),
                      Number(ticket.max_per_order || 0)
                    );

                    return (
                      <div className="tb-ticket-card" key={ticket.id}>
                        <div className="tb-ticket-card-head">
                          <div className="tb-ticket-name-wrap">
                            <div className="tb-ticket-name">{ticket.name}</div>
                            <div className="tb-ticket-desc">
                              {ticket.description || "Không có mô tả"}
                            </div>
                          </div>

                          <div className="tb-ticket-price">
                            {Number(ticket.price || 0).toLocaleString("vi-VN")} đ
                          </div>
                        </div>

                        <div className="tb-ticket-body">
                          <ul className="tb-ticket-features">
                            <li>Còn lại: {ticket.available ?? 0} vé</li>
                            <li>Tối đa mỗi đơn: {ticket.max_per_order ?? 0} vé</li>
                            <li>
                              Chuyển nhượng:{" "}
                              {Number(ticket.transferable) === 1 ? "Có" : "Không"}
                            </li>
                          </ul>

                          <div className="tb-ticket-qty-box">
                            <Form.Label className="mb-2 text-white fw-semibold">
                              Chọn số lượng
                            </Form.Label>
                            <Form.Control
                              type="number"
                              min={0}
                              max={maxAllowed}
                              value={quantities[ticket.id] || 0}
                              onChange={(e) =>
                                handleQuantityChange(ticket, e.target.value)
                              }
                              disabled={maxAllowed <= 0}
                            />
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </section>

            <section className="tb-detail-description">
              <div className="tb-ticket-section-title">Mô tả sự kiện</div>
              <div className="tb-detail-description-text">
                {event.description || "Chưa có mô tả cho sự kiện này."}
              </div>
            </section>
          </Col>

          <Col lg={3}>
            <aside className="tb-order-summary">
              <div className="tb-order-title">Tóm tắt đơn hàng</div>

              <div className="tb-order-row">
                <span>Tổng loại vé</span>
                <strong>{ticketTypes.length}</strong>
              </div>

              <div className="tb-order-row">
                <span>Tổng số vé</span>
                <strong>{totalTickets}</strong>
              </div>

              <div className="tb-order-row total">
                <span>Tổng tiền</span>
                <strong>{totalAmount.toLocaleString("vi-VN")} đ</strong>
              </div>

              {summary && (
                <div className="tb-order-summary-box">
                  <div className="tb-order-mini-row">
                    <span>Tổng số lượng</span>
                    <strong>{summary.totalQuantity ?? 0}</strong>
                  </div>
                  <div className="tb-order-mini-row">
                    <span>Đã bán</span>
                    <strong>{summary.totalSold ?? 0}</strong>
                  </div>
                  <div className="tb-order-mini-row">
                    <span>Còn lại</span>
                    <strong>{summary.totalAvailable ?? 0}</strong>
                  </div>
                </div>
              )}

              <Button
                className="tb-buy-main-btn mt-3"
                onClick={handleCreateOrder}
                disabled={!canBuy || totalTickets === 0 || submitting}
              >
                {submitting ? "Đang tạo đơn..." : "Mua vé ngay"}
              </Button>

              {!user && (
                <Alert variant="warning" className="mt-3 mb-0">
                  Bạn cần đăng nhập trước khi đặt vé.
                </Alert>
              )}
            </aside>
          </Col>
        </Row>
      </Container>
    </div>
  );
}

export default EventDetailPage;
